import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './TopWorstSellers.css';
import Optionbar from './Optionbar';

import beerIcon from './Icons/beer.svg';
import cocktailIcon from './Icons/cocktail.svg';
import coffeeIcon from './Icons/coffee.svg';
import juicesIcon from './Icons/juices.svg';
import mocktailsIcon from './Icons/mocktails.svg';
import softdrinksIcon from './Icons/softdrinks.svg';
import spiritsIcon from './Icons/spirits.svg';
import sportdrinksIcon from './Icons/sportdrinks.svg';
import teaIcon from './Icons/tea.svg';
import wineIcon from './Icons/wine.svg';
import highMarginIcon from './Icons/highmargin.svg';
import trendingIcon   from './Icons/trending.svg';
import ecoIcon        from './Icons/ecofriendly.svg';
import summerIcon     from './Icons/summer.svg';
import winterIcon     from './Icons/winter.svg';
import autumnIcon     from './Icons/autumn.svg';
import springIcon     from './Icons/spring.svg';

const categoryIconMap = { Beer: beerIcon, Cocktail: cocktailIcon, Coffee: coffeeIcon, Juices: juicesIcon, Mocktails: mocktailsIcon, 'Soft Drinks': softdrinksIcon, Spirits: spiritsIcon, 'Sport/Energy Drinks': sportdrinksIcon, 'Tea & Infusions': teaIcon, Wine: wineIcon };
const seasonIconMap   = { Summer: summerIcon, Winter: winterIcon, Autumn: autumnIcon, Spring: springIcon };

const TopWorstSellers = () => {
    const [searchTerm, setSearchTerm] = useState('');
    const [sortOrder, setSortOrder]   = useState('top');
    const [items, setItems]           = useState([]);
    const [loading, setLoading]       = useState(true);
    const [error, setError]           = useState(null);

    useEffect(() => {
        (async () => {
            setLoading(true);
            try {
                const { data } = await axios.get('http://localhost:3007/api/sales', { withCredentials: true });
                setItems(data.map(i => ({ name: i.item_name, count: i.sold_count, category: i.category_name, high_margin: i.is_high_margin===1, trending: i.is_trending===1, eco_friendly: i.eco_friendly===1, season: i.season })));
            } catch (e) { console.error(e); setError('Kon verkoopcijfers niet laden'); }
            setLoading(false);
        })();
    }, []);

    if (loading) return <p>Loading…</p>;
    if (error)   return <p className="error">{error}</p>;

    const sortedItems = [...items].sort((a,b) => sortOrder==='top'?b.count-a.count:a.count-b.count);
    const visible     = sortedItems.filter(i=>i.name.toLowerCase().includes(searchTerm.toLowerCase()));

    return (
        <div className="top-worst-container">
            <div className="centre-content">
                <div className="segment-section"><h2 className="section-title">Top & Worst</h2></div>
                <div className="items-section">
                    <div className="list-header">{/*...header code...*/}</div>
                    <ul className="items-list">
                        {visible.map((item,idx)=>(
                            <li key={idx} className="item">
                                <div className="item-main"><span>{idx+1}.</span><span>{item.name}</span></div>
                                <div className="item-tags">
                                    {item.category && categoryIconMap[item.category] && <img src={categoryIconMap[item.category]} className="tag-icon" alt={item.category}/>}
                                    {item.high_margin && <img src={highMarginIcon} className="tag-icon" alt="High Margin"/>}
                                    {item.trending    && <img src={trendingIcon}   className="tag-icon" alt="Trending"/>}
                                    {item.eco_friendly&& <img src={ecoIcon}        className="tag-icon" alt="Eco Friendly"/>}
                                    {item.season in seasonIconMap && <img src={seasonIconMap[item.season]} className="tag-icon" alt={item.season}/>}
                                </div>
                                <span className="item-count">{item.count} sold</span>
                            </li>
                        ))}
                    </ul>
                </div>
            </div>
            <Optionbar filters={filters} onChange={setFilters} />  {/* stays at right */}
        </div>
    );
};

export default TopWorstSellers;
